import sys
from collections import deque
from typing import List

class Solution:
    def ladderLength(self, beginWord: str, endWord: str, wordList: List[str]) -> int:
        word_set = set(wordList)
        if endWord not in word_set:
            return 0
        # Ensure beginWord is in the set for neighbor generation
        word_set.add(beginWord)
        L = len(beginWord)
        # Preprocess: generic intermediate states
        all_combo_dict = {}
        for word in word_set:
            for i in range(L):
                key = word[:i] + '*' + word[i+1:]
                all_combo_dict.setdefault(key, []).append(word)
        # BFS
        queue = deque([(beginWord, 1)])
        visited = {beginWord}
        while queue:
            current_word, level = queue.popleft()
            for i in range(L):
                intermediate = current_word[:i] + '*' + current_word[i+1:]
                for neighbor in all_combo_dict.get(intermediate, []):
                    if neighbor == endWord:
                        return level + 1
                    if neighbor not in visited:
                        visited.add(neighbor)
                        queue.append((neighbor, level + 1))
                # optional clear to save memory
                # all_combo_dict[intermediate] = []
        return 0

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        begin = next(it)
        end = next(it)
        n = int(next(it))
        words = [next(it) for _ in range(n)]
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.ladderLength(begin, end, words)
    print(ans)

