#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int ladderLength(string beginWord, string endWord, vector<string>& wordList) {
        unordered_set<string> wordSet(wordList.begin(), wordList.end());
        if (wordSet.find(endWord) == wordSet.end()) return 0;
        wordSet.insert(beginWord);
        int L = beginWord.size();
        unordered_map<string, vector<string>> comboMap;
        for (const string& word : wordSet) {
            for (int i = 0; i < L; ++i) {
                string key = word;
                key[i] = '*';
                comboMap[key].push_back(word);
            }
        }
        queue<pair<string,int>> q;
        q.push({beginWord,1});
        unordered_set<string> visited;
        visited.insert(beginWord);
        while (!q.empty()) {
            auto _tmp_binding_0 = q.front(); auto cur = _tmp_binding_0.first; auto level = _tmp_binding_0.second; q.pop();
            for (int i = 0; i < L; ++i) {
                string key = cur;
                key[i] = '*';
                auto it = comboMap.find(key);
                if (it == comboMap.end()) continue;
                for (const string& nxt : it->second) {
                    if (nxt == endWord) return level + 1;
                    if (visited.find(nxt) == visited.end()) {
                        visited.insert(nxt);
                        q.push({nxt, level + 1});
                    }
                }
                // optional clear to reduce future loops
                // it->second.clear();
            }
        }
        return 0;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    string beginWord, endWord;
    if (!(cin >> beginWord)) return 0;
    if (!(cin >> endWord)) return 0;
    int n; if (!(cin >> n)) return 0;
    vector<string> wordList(n);
    for (int i = 0; i < n; ++i) cin >> wordList[i];
    Solution sol;
    int ans = sol.ladderLength(beginWord, endWord, wordList);
    cout << ans << "\n";
    return 0;
}
